import{bV as r,aL as a,u as e,G as o}from"./chunks/framework.C5oj02QE.js";const b=JSON.parse('{"title":"Spring Boot Starter","description":"理解 Spring Boot Starter 的作用、依赖组合和自定义 Starter 思路","frontmatter":{"title":"Spring Boot Starter","description":"理解 Spring Boot Starter 的作用、依赖组合和自定义 Starter 思路","outline":"deep"},"headers":[],"relativePath":"backend/spring-boot/starter.md","filePath":"backend/spring-boot/starter.md","lastUpdated":1780922851000}'),s={name:"backend/spring-boot/starter.md"};function d(n,t,i,p,l,c){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="spring-boot-starter" tabindex="-1">Spring Boot Starter <a class="header-anchor" href="#spring-boot-starter" aria-label="Permalink to &quot;Spring Boot Starter&quot;">​</a></h1><p>Starter 是一组依赖和默认配置的组合。引入 Starter 后，项目可以快速获得某类能力，例如 Web、数据库、缓存或安全认证。</p><h2 id="常见-starter" tabindex="-1">常见 Starter <a class="header-anchor" href="#常见-starter" aria-label="Permalink to &quot;常见 Starter&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Starter</th><th>作用</th></tr></thead><tbody><tr><td><code>spring-boot-starter-web</code></td><td>Web MVC 和内嵌服务器</td></tr><tr><td><code>spring-boot-starter-validation</code></td><td>参数校验</td></tr><tr><td><code>spring-boot-starter-data-jpa</code></td><td>JPA 数据访问</td></tr><tr><td><code>spring-boot-starter-actuator</code></td><td>健康检查和指标</td></tr></tbody></table><p>Starter 本身通常不写业务逻辑，而是把相关依赖聚合起来。</p><h2 id="starter-与自动配置" tabindex="-1">Starter 与自动配置 <a class="header-anchor" href="#starter-与自动配置" aria-label="Permalink to &quot;Starter 与自动配置&quot;">​</a></h2><p>Starter 负责引入依赖，自动配置负责根据依赖创建 Bean。两者配合，才形成“引入即用”的开发体验。</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>引入 Starter -&gt; classpath 出现相关类 -&gt; 自动配置条件满足 -&gt; 创建默认 Bean</span></span></code></pre></div><h2 id="自定义-starter" tabindex="-1">自定义 Starter <a class="header-anchor" href="#自定义-starter" aria-label="Permalink to &quot;自定义 Starter&quot;">​</a></h2><p>内部平台或公共能力可以封装成 Starter，例如统一日志、统一鉴权、统一异常处理。这样多个项目可以共享同一套基础设施。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>理解 Starter 后，就能知道一个功能是怎么被引入项目的。排查依赖冲突或功能不生效时，也能沿着 Starter 和自动配置继续分析。</p>',12)])])}const S=r(s,[["render",d]]);export{b as __pageData,S as default};
